diffs.patch:
Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,24 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  for (let i = 0; i < argv.length; i += 1) {
+    const arg = argv[i]
+    if (!arg.startsWith('--')) {
+      result._.push(arg)
+      continue
+    }
+    if (arg.includes('=')) {
+      const eqIndex = arg.indexOf('=')
+      const key = arg.slice(2, eqIndex)
+      const value = arg.slice(eqIndex + 1)
+      result[key] = value
+      continue
+    }
+    if (i + 1 < argv.length && argv[i + 1] && argv[i + 1].startsWith('--') === false) {
+      result[arg.slice(2)] = argv[i + 1]
+      i += 1
+      continue
+    }
+    result[arg.slice(2)] = true
   }
   return result
 }
